import{_ as o,c as r,o as n,ag as s}from"./chunks/framework.DVUBUV_u.js";const c=JSON.parse('{"title":"Персонализация","description":"","frontmatter":{"title":"Персонализация"},"headers":[],"relativePath":"ru/options/customize.md","filePath":"ru/options/customize.md"}'),e={name:"ru/options/customize.md"};function a(d,t,g,i,l,h){return n(),r("div",null,[...t[0]||(t[0]=[s('<h1 id="персонализация-customize" tabindex="-1">Персонализация (Customize) <a class="header-anchor" href="#персонализация-customize" aria-label="Permalink to &quot;Персонализация (Customize)&quot;">​</a></h1><p>В <strong>Options → General → Customize</strong> собраны настройки внешнего вида основного окна инспектора: тема, фоновое медиа и параметры его отображения. Оформляется панель инструмента, а не открытый сайт.</p><hr><h2 id="расширение-и-standalone-что-отличается-в-customize" tabindex="-1">Расширение и Standalone: что отличается в Customize <a class="header-anchor" href="#расширение-и-standalone-что-отличается-в-customize" aria-label="Permalink to &quot;Расширение и Standalone: что отличается в Customize&quot;">​</a></h2><p>Набор полей (<strong>тема</strong>, <strong>файл / ссылка</strong>, прозрачность, размытие, шум, позиция, масштаб) <strong>одинаковый</strong>. Отличается то, <strong>куда складываются локальные копии файлов</strong> и <strong>есть ли учёт общего лимита по размеру</strong>.</p><table tabindex="0"><thead><tr><th></th><th><strong>Расширение (Chrome / Edge)</strong></th><th><strong>Автономный режим (Standalone)</strong></th></tr></thead><tbody><tr><td><strong>Где хранятся выбранные файлы</strong></td><td>Копии медиа пишутся в <strong>IndexedDB</strong> контекста расширения (отдельные хранилища под обои и прочие сохранённые файлы).</td><td>Медиа для оформления уходит в <strong>единое локальное хранилище</strong> приложения (центральное хранилище с лимитом).</td></tr><tr><td><strong>Лимит по объёму</strong></td><td>Отдельного лимита «N МБ на медиа» в приложении <strong>нет</strong>; реальное ограничение — <strong>квота IndexedDB / хранилища</strong> в рамках профиля браузера для расширения.</td><td><strong>Жёсткий лимит 30 МБ</strong> на <strong>суммарный</strong> размер медиа в хранилище standalone: при добавлении проверяется новый суммарный объём; при превышении сохранение <strong>блокируется</strong> (ошибка вида «Media limit exceeded»).</td></tr><tr><td><strong>Индикатор заполнения</strong></td><td>Счётчик «X МБ / 30 МБ» в Customize <strong>не показывается</strong>.</td><td>В Customize отображается <strong>прогресс использования</strong> медиа-хранилища (занято <strong>МБ</strong> из <strong>30 МБ</strong>), чтобы было видно, сколько места осталось под новые фоны и файлы.</td></tr></tbody></table><p>Фон по <strong>URL</strong> в обоих режимах не «весит» в локальном медиа-квотинге инспектора так же, как загруженный файл — но для офлайн и предсказуемости обычно удобнее сохранять файл локально в пределах квоты (в Standalone — с учётом <strong>30 МБ</strong> суммарно).</p><hr><h2 id="тема" tabindex="-1">Тема <a class="header-anchor" href="#тема" aria-label="Permalink to &quot;Тема&quot;">​</a></h2><p><strong>Dark / Light</strong> — переключение светлой и тёмной цветовой схемы интерфейса инспектора.</p><hr><h2 id="фон-image" tabindex="-1">Фон (Image) <a class="header-anchor" href="#фон-image" aria-label="Permalink to &quot;Фон (Image)&quot;">​</a></h2><p>Блок <strong>Image</strong> задаёт фон панели. Доступны два источника — <strong>File</strong> и <strong>Link</strong>:</p><ul><li><strong>Файл</strong> — локальный ресурс. Можно выбрать через <strong>Browse</strong> или из списка ранее сохранённых копий (расширение: IndexedDB; standalone: единое хранилище с лимитом <strong>30 МБ</strong> — см. таблицу выше). Про наборы настроек — <a href="/docs/ru/options/settings_management.html">Менеджер настроек</a>.</li><li><strong>Ссылка</strong> — указать URL медиа по ссылке.</li></ul><p>Поддерживаются <strong>статичные изображения</strong>, анимированные <strong><code>GIF</code></strong> и фоновое видео <strong><code>MP4</code></strong>.</p><hr><h2 id="параметры-отображения-фона" tabindex="-1">Параметры отображения фона <a class="header-anchor" href="#параметры-отображения-фона" aria-label="Permalink to &quot;Параметры отображения фона&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Параметр</th><th>Назначение</th></tr></thead><tbody><tr><td><strong>Image Opacity</strong></td><td>Прозрачность фонового слоя относительно интерфейса.</td></tr><tr><td><strong>Blur</strong></td><td>Размытие фона.</td></tr><tr><td><strong>Noise Intensity / Opacity</strong></td><td>Наложение и сила шумового слоя поверх фона (для текстуры/«зернистости»).</td></tr><tr><td><strong>Position (X / Y)</strong></td><td>Смещение изображения по горизонтали и вертикали.</td></tr><tr><td><strong>Scale</strong></td><td>Масштаб фона в процентах; допустимый диапазон <strong>100–200%</strong>.</td></tr></tbody></table><p>Комбинация прозрачности, размытия и шума позволяет сделать фон заметным или почти нейтральным, не мешая чтению данных во вкладках.</p><hr><h2 id="см-также" tabindex="-1">См. также <a class="header-anchor" href="#см-также" aria-label="Permalink to &quot;См. также&quot;">​</a></h2><ul><li><a href="/docs/ru/options/display_mode.html">Режимы отображения</a></li><li><a href="/docs/ru/options/settings_management.html">Менеджер настроек</a></li></ul>',22)])])}const u=o(e,[["render",a]]);export{c as __pageData,u as default};
